def safe_average(nums):
    # BUG: on an empty list this does sum([]) / len([]) == 0 / 0
    # which raises ZeroDivisionError. Add a guard clause so an
    # empty list returns 0.0, and keep the happy path unchanged.
    return sum(nums) / len(nums)

print(safe_average([]))
